/**
 * Static algorithm database — every set scraped from speedcubedb.com.
 *
 * Use {@link loadAlg} to lazy-import a (puzzle, set) pair. Each JSON is
 * code-split by Vite, so only opened sets ship to the browser.
 *
 * Data is generated by `scramble-stats-build/bin/scrape_speedcubedb.ts`.
 */

export interface AlgEntry {
  alg: string;
  altId?: string;
  /** YouTube finger-tricks tutorial id (no full URL — caller composes) */
  ytId?: string;
}

export type AlgSticker =
  | { kind: 'f2l'; fl: string }
  | { kind: 'face'; us: string; ub: string; uf: string; ul: string; ur: string }
  | { kind: 'raw'; tag: string; attrs: Record<string, string> };

export interface AlgCase {
  /** PG `alg_cases.id` — populated by API responses; absent in legacy code paths. */
  id?: number;
  name: string;
  subgroup: string;
  setup: string;
  standard?: string;
  sticker: AlgSticker;
  /** F2L: 4 entries (FR / FL / BL / BR). Most others: single entry. */
  algs: AlgEntry[][];
  /** F2L only — names of each orientation tab (e.g. "Front Right") */
  oriNames?: string[];
  /** ZBLS only — links cases into the trainer's grid layout. */
  trainerKey?: string;
}

export interface AlgFile {
  scrapedAt: string;
  source: string;
  /** "2x2" | "3x3" | "4x4" | "5x5" */
  puzzle: string;
  /** slug — e.g. "f2l", "zbll", "ortega-oll", "oll-parity" */
  set: string;
  cases: AlgCase[];
}

export type AlgPuzzle = '2x2' | '3x3' | '4x4' | '5x5' | 'sq1' | 'megaminx' | 'pyraminx' | 'skewb';

/** 3x3 set slug — matches `slug` in {@link ALG_CATALOG['3x3']}. */
export type Alg3x3Set =
  | 'f2l' | 'adv-f2l' | 'oll' | 'pll'
  | 'coll' | 'wv' | 'cmll' | 'sbls' | 'eo4a' | 'anti-pll' | 'sv' | 'ell' | 'fruf'
  | 'cls' | 'vls' | 'ollcp' | 'zbll' | '1lll' | 'zbls';

/** Catalogue of available sets per puzzle (display name + slug). Drives the index pages. */
export interface AlgSetMeta {
  /** URL slug (matches data filename: alg_<puzzle>_<slug>.json) */
  slug: string;
  /** Speedcubedb subset key (just for reference; not used at runtime) */
  scd: string;
  en: string;
  zh: string;
  /** True for sets that speedcubedb organises under sub-pages (ZBLL → ZBLL U/L/T/...).
   *  UI shows a subgroup-picker landing page first, then cases for the picked subgroup. */
  umbrella?: boolean;
}

